const input = $input.first().json.body || $input.first().json || {};

const verification = {
  verification_id: `verify_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
  target_type: input.target_type || 'elevenlabs',
  agent_id: input.agent_id || null,
  workflow_id: input.workflow_id || null,
  fix_applied: input.fix_applied || {},
  metrics_before: input.metrics_before || {},
  cooldown_ms: input.cooldown_ms || 30000,
  max_retries: input.max_retries || 1,
  current_retry: 0,
  started_at: new Date().toISOString()
};

return [{ json: verification }];

const verificationReq = $('Parse Verification Request').item.json;
const newResults = $input.first().json;

const metricsBefore = verificationReq.metrics_before;
let metricsAfter = {};
let outcome = 'unchanged';

if (verificationReq.target_type === 'elevenlabs') {
  const evalData = newResults.evaluation || newResults;
  metricsAfter = {
    pass_rate: parseFloat(evalData.summary?.pass_rate || '0'),
    tool_accuracy: parseFloat(evalData.summary?.avg_tool_accuracy || '0'),
    criteria_score: parseFloat(evalData.summary?.avg_criteria_score || '0'),
    failed: evalData.summary?.failed || 0
  };

  const beforePassRate = metricsBefore.pass_rate || 0;
  const afterPassRate = metricsAfter.pass_rate;

  if (afterPassRate > beforePassRate + 5) {
    outcome = 'improved';
  } else if (afterPassRate < beforePassRate - 5) {
    outcome = 'degraded';
  }
} else {
  metricsAfter = {
    pass_rate: parseFloat(newResults.summary?.pass_rate || '0'),
    avg_latency_ms: newResults.summary?.avg_latency_ms || 0,
    failed: newResults.summary?.failed || 0
  };

  const beforePassRate = metricsBefore.pass_rate || 0;
  const afterPassRate = metricsAfter.pass_rate;

  if (afterPassRate > beforePassRate + 5) {
    outcome = 'improved';
  } else if (afterPassRate < beforePassRate - 5) {
    outcome = 'degraded';
  }
}

const result = {
  verification_id: verificationReq.verification_id,
  target_type: verificationReq.target_type,
  agent_id: verificationReq.agent_id,
  workflow_id: verificationReq.workflow_id,
  fix_applied: verificationReq.fix_applied,
  metrics_before: metricsBefore,
  metrics_after: metricsAfter,
  outcome: outcome,
  improvement_delta: metricsAfter.pass_rate - (metricsBefore.pass_rate || 0),
  completed_at: new Date().toISOString()
};

return [{ json: result }];

const result = $input.first().json;

console.log(`[simulation-review] Verification SUCCESS: ${result.verification_id}`);
console.log(`[simulation-review] Outcome: ${result.outcome}, Delta: +${result.improvement_delta.toFixed(1)}%`);

return [{ json: { ...result, action: 'logged', notification: 'success_slack_pending' } }];

const result = $input.first().json;

console.log(`[simulation-review] Verification FAILED - ROLLBACK NEEDED: ${result.verification_id}`);
console.log(`[simulation-review] Outcome: ${result.outcome}, Delta: ${result.improvement_delta.toFixed(1)}%`);

return [{ json: { ...result, action: 'rollback_queued', notification: 'alert_slack_pending', rollback_instructions: 'Manual rollback required - restore previous prompt version' } }];

const result = $input.first().json;

console.log(`[simulation-review] Verification UNCHANGED: ${result.verification_id}`);
console.log(`[simulation-review] No significant change detected. Queuing for manual review.`);

return [{ json: { ...result, action: 'manual_review', notification: 'review_slack_pending' } }];
